SET academy_metadata = '{"displayName":"Canada – Student Visa (Study Permit — Outside Canada)","shortDescription":"IRCC study permit · SDS & Non-SDS pathways · DLI required","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 4 Jun 2026","learningLevel":"Intermediate","learningMinutes":20,"policyAlert":{"active":true,"date":"4 Jun 2026","summary":"Confirm current IRCC study permit fee and biometrics fee on canada.ca before sharing quotes with clients."},"alert":{"title":"SDS stream status","body":"Verify whether SDS is available for the client''s country of residence before promising timelines. Use Non-SDS when SDS is paused or ineligible."},"tags":[{"label":"Active service","variant":"success"},{"label":"SDS check required","variant":"warning"},{"label":"8–12 weeks","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"8–12 weeks processing","variant":"neutral"},{"label":"Biometrics required","variant":"neutral"},{"label":"DLI letter mandatory","variant":"success"},{"label":"GIC if SDS","variant":"warning"}],"kpis":[{"label":"Processing time","value":"8–12w","sub":"Varies by country & stream","tone":"primary"},{"label":"Government fee","value":"CAD $150","sub":"+ biometrics if applicable","tone":"warning"},{"label":"Our approval rate","value":"87%","sub":"~72% industry benchmark","tone":"success"},{"label":"Required docs","value":"14","sub":"+ conditional items","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & third-party","tone":"primary"}],"about":[{"label":"Description","value":"Study permit allowing international students to study at a Designated Learning Institution (DLI) in Canada. This service is for applicants applying from outside Canada before travel; application is typically online via IRCC portal, and biometrics and medical may apply."},{"label":"Eligible applicants","value":"Valid LOA from DLI · Proof of funds · Clean immigration history · Genuine student intent"},{"label":"Application streams","value":"SDS (where eligible): faster processing with GIC and language scores. Non-SDS: standard study permit pathway.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Client receives POE letter / permit details; explain study conditions, work limits, and DLI enrollment obligations."}],"eligibility":[{"criterion":"Letter of acceptance (LOA) from DLI","met":true,"note":"LOA must be valid and program start date realistic"},{"criterion":"Proof of financial support (tuition + living)","met":true,"note":"SDS: GIC + tuition payment proof where required"},{"criterion":"Language proficiency (SDS)","met":false,"note":"IELTS/TOEFL/PTE per SDS country list"},{"criterion":"Biometrics completed","met":false,"note":"Book within 30 days of BIL if required"},{"criterion":"Medical exam (if required)","met":false,"note":"Based on residence history and IRCC instructions"},{"criterion":"No criminal / immigration misrepresentation","met":true},{"criterion":"Genuine student / ties to home country","met":true,"note":"SOP and career plan must align"}],"redFlagsBanner":"If refused, do not reapply with the same weak documents. Address the specific refusal reason in writing before a new submission.","redFlags":[{"title":"Insufficient or unseasoned funds","description":"Large recent deposits, funds not aligned with sponsor income, or missing 4–6 month bank history.","fix":"Season funds early; use GIC for SDS; sponsor ITR + employment letters","severity":"Very common"},{"title":"Weak or generic SOP","description":"Template SOP, course mismatch with past education, or unclear return intent.","fix":"Course-specific SOP; link prior study/work to Canada program; clear post-study plan","severity":"Common"},{"title":"Wrong stream (SDS vs Non-SDS)","description":"Applied SDS without meeting language/GIC/tuition requirements.","fix":"Re-check SDS eligibility by country of residence; switch stream and re-quote fees","severity":"Common"},{"title":"LOA / DLI issues","description":"Expired LOA, non-DLI institution, or start date passed.","fix":"Verify DLI list on canada.ca; request updated LOA from institution","severity":"High"},{"title":"Previous refusals not explained","description":"Canada or other country refusals not disclosed or addressed in cover letter.","fix":"Full disclosure + changed circumstances + stronger evidence package","severity":"High"},{"title":"Medical or biometrics overdue","description":"BIL expired or medical not completed in time.","fix":"Track BIL deadline; book VAC slot immediately; upload confirmation","severity":"Medium"}],"faqs":[{"q":"Can we switch from SDS to Non-SDS if SDS is paused?","a":"Yes, when the client is SDS-ineligible or SDS is unavailable. Rebuild the file per Non-SDS checklist and update fee quote (no GIC requirement unless otherwise applicable)."},{"q":"How much funds to show for Non-SDS?","a":"Tuition for first year plus living expenses per IRCC guidelines (amounts update—verify on canada.ca). Include credible source of funds and history."},{"q":"When should biometrics be done?","a":"As soon as possible after Biometric Instruction Letter (BIL), typically within 30 days. Counselor should track VAC appointment confirmation."},{"q":"Can spouse/children accompany?","a":"May require separate applications (visitor permit, OWP, study permit for children). Assess dependants case-by-case; extra funds and ties evidence needed."},{"q":"What if LOA start date is near?","a":"Apply urgently; explain delay if any. If start date passed, obtain updated LOA before submission."},{"q":"Is medical mandatory for everyone?","a":"No—depends on country of residence and stay duration. Follow IRCC medical instructions for the client''s profile."},{"q":"Can client work on study permit?","a":"Generally on-campus without separate permit; off-campus rules have hour limits—cite current IRCC rules at time of counseling."},{"q":"What happens after study permit approval?","a":"Client receives introduction letter; permit issued at port of entry or as directed. Remind client to maintain full-time status and keep contact details updated with IRCC."}],"compliance":["Paid representation in Canada may require RCIC/L lawyer—confirm who signs client agreement","Client service agreement and consent must be on file before submission","Never guarantee visa approval; use approved-language only in marketing","Fee quotes must separate consultancy, government, and third-party (GIC, medical, biometrics)"],"proTips":["Verify DLI status on the official list before taking fees for submission","Book biometrics within days of BIL—delays are a top preventable refusal factor","For SDS, pre-validate language scores and GIC bank list","Use a submission checklist sign-off before uploading to IRCC portal","Save final PDF package in client binder for audit"],"postApproval":["Send POE / permit summary and enrollment deadlines to client in writing","Remind client of study permit conditions and DLI enrollment date","Discuss PGWP eligibility timeline (program length and DLI matter)","Register client for pre-departure briefing if your office offers it"],"performance":{"ourRate":87,"industryRate":72,"stats":[{"label":"Files this year","value":"143"},{"label":"Approved","value":"124"},{"label":"Refused","value":"12"},{"label":"Withdrawn","value":"7"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":87,"benchmark":72},{"label":"Financial documentation","ours":82,"benchmark":68},{"label":"SOP quality","ours":79,"benchmark":65},{"label":"Complete checklist first submit","ours":91,"benchmark":70}],"timeline":[{"weeks":"1–2","title":"Counseling, LOA review, fee agreement"},{"weeks":"2–4","title":"Document collection, SOP, financials"},{"weeks":"4–5","title":"Quality review & IRCC submission"},{"weeks":"5–6","title":"Biometrics / medical (if applicable)"},{"weeks":"8–12","title":"IRCC processing (stream-dependent)"}],"relatedServices":[{"label":"Canada – PGWP","libraryId":""},{"label":"Canada – Visitor Visa","libraryId":""},{"label":"Canada – Spouse Open Work Permit","libraryId":""}],"changelog":[{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v2.4","date":"4 Jun 2026","author":"Service Library","summary":"Updated fees note, SDS check reminder, expanded red flags and FAQs."},{"version":"v2.3","date":"28 May 2025","author":"Admin","summary":"Government fee and processing time review."}],"staffNotes":[{"author":"Documentation team","date":"4 Jun 2026","text":"Always confirm SDS eligibility on canada.ca for client''s country of residence before promising 20-day processing. GIC bank must be on approved list."},{"author":"Quality","date":"1 Jun 2026","text":"Second review required for all files with prior Canada refusal."}],"resources":[{"title":"IRCC — Study permit","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit.html","description":"Official requirements, how to apply, and after you apply"},{"title":"List of designated learning institutions (DLI)","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit/prepare/designated-learning-institutions-list.html","description":"Verify institution before LOA and fee collection"},{"title":"Student Direct Stream (SDS)","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit/student-direct-stream.html","description":"Eligibility by country of residence"},{"title":"Biometrics","url":"https://www.canada.ca/en/immigration-refugees-citizenship/campaigns/biometrics/facts.html","description":"When required and how to book after BIL"},{"title":"IRCC processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current estimates by country and application type"},{"title":"GIC — Participating financial institutions","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit/student-direct-stream/eligible-gic.html","description":"Approved banks for SDS GIC"}],"quiz":[{"level":1,"question":"In a study permit application made from outside Canada, which statement about the basic purpose of a study permit is correct?","options":["A study permit authorizes a foreign national to study at a designated learning institution in Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The permit is status authorization for studies; it is not the school admission letter itself."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about a designated learning institution is correct?","options":["The school must be a DLI with a valid DLI number for most post-secondary study permit applications.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC normally requires acceptance by a recognized DLI before issuing a study permit."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about the letter of acceptance is correct?","options":["A valid LOA from the DLI is core evidence that the applicant has been admitted to a real program.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The LOA anchors the program, start date, school, and study plan reviewed by the officer."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about the study permit processing fee is correct?","options":["The standard IRCC study permit application fee is CAD $150, separate from biometrics where required.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Fees can change, but CAD $150 is the standard study permit fee and biometrics are charged separately."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about biometrics is correct?","options":["Most applicants between 14 and 79 must give biometrics unless an exemption or still-valid biometrics applies.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Biometrics are identity screening evidence and are not the same as a medical exam."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about proof of funds is correct?","options":["The applicant must show enough money for tuition, living costs, and travel, using credible documents.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Financial sufficiency is a central temporary residence requirement for students."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about SDS eligibility is correct?","options":["Student Direct Stream is available only to residents of specified countries who meet strict upfront evidence requirements.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"SDS is a faster stream, not a universal right for every study permit applicant."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about non-SDS applications is correct?","options":["Non-SDS applications can still be approved if the applicant satisfies the officer on funds, purpose, and admissibility.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Non-SDS is the regular route and does not mean the application is weak by default."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about a port of entry letter is correct?","options":["A POE letter of introduction is an approval letter used to obtain the actual study permit when entering Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The POE letter is not itself the permit; the border officer issues the permit document."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about TRV or eTA after approval is correct?","options":["If required, IRCC normally issues or facilitates the entry document after approving the study permit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The study permit approval and entry document work together but serve different purposes."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about Quebec studies is correct?","options":["Most students studying in Quebec need a CAQ before IRCC can finalize the study permit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Quebec has an additional provincial acceptance step for many international students."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about provincial or territorial attestation is correct?","options":["Many post-secondary applicants need a PAL or TAL unless an IRCC exemption applies.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The attestation supports allocation under Canada''s study permit intake controls."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about passport validity is correct?","options":["A study permit cannot normally be issued beyond the passport expiry date.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Passport validity can shorten the permit even when the program is longer."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about temporary resident intent is correct?","options":["The applicant must satisfy IRCC they will leave Canada when authorized stay ends, even if they may later seek PR.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Dual intent is allowed, but the temporary plan must still be credible."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about medical exams is correct?","options":["A medical exam may be required based on country of residence, program, work in health settings, or IRCC instructions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Medical requirements are tied to admissibility and public health screening."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about custodianship for minors is correct?","options":["Minor students may need a custodian declaration depending on age, province, and living arrangements.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC assesses whether a minor will have proper care and support in Canada."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about work while studying is correct?","options":["Eligible full-time students at participating DLIs may work only within the conditions printed or implied by IRCC rules.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Work authorization is conditional and does not apply to every student or program."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about program credibility is correct?","options":["The chosen program should make sense against the applicant''s education, employment, and future plans.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Officers assess whether the study plan appears genuine and logical."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about family members is correct?","options":["Spouses or children can apply with the student, but each person must qualify for their own temporary resident document.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Accompanying family does not remove the student''s burden to prove eligibility."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about misrepresentation is correct?","options":["False documents or withheld refusals can cause refusal and a five-year inadmissibility finding.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Accuracy is essential because IRCC cross-checks records and documents."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about language evidence is correct?","options":["Language test results may be required by the school or stream, and can also support study readiness.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Language evidence helps show the applicant can realistically complete the program."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about tuition payment is correct?","options":["Tuition receipts are useful financial evidence, especially for SDS, but they do not guarantee approval.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Payment supports seriousness and funding, while the officer still reviews all criteria."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about GIC evidence is correct?","options":["A Guaranteed Investment Certificate is a common SDS financial requirement for eligible applicants.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The GIC shows available living funds under SDS but does not replace every other eligibility requirement."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about admissibility is correct?","options":["Criminality, medical issues, security concerns, or prior immigration breaches can make a student inadmissible.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Study permit eligibility includes both program-related and admissibility screening."},{"level":1,"question":"In a study permit application made from outside Canada, which statement about final permit issuance is correct?","options":["The final study permit document is usually printed by CBSA at the port of entry for outside-Canada approvals.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Applicants should inspect the printed permit for correct school, work, and expiry conditions."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about creating the online application?","options":["The applicant normally submits the study permit package through an IRCC secure account or portal with digital forms and uploads.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Online submission creates the file, document checklist, fee payment, and message channel."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about IMM 1294?","options":["IMM 1294 is the main application form for a study permit made outside Canada.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The form captures identity, education, intended study, background, and family information."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about family information form?","options":["IMM 5707 or IMM 5645 may be required depending on the applicant''s country-specific checklist.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC uses family details for identity, background, and consistency checks."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about country-specific instructions?","options":["The visa office checklist can require extra documents such as police certificates, education records, or civil documents.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A complete application follows both general IRCC requirements and local instructions."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about biometrics timing?","options":["After paying the biometrics fee, IRCC issues a biometrics instruction letter and the applicant books a VAC appointment.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Biometrics are normally given after the instruction letter, not before the application exists."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about upfront medicals?","options":["If an upfront medical is used, the applicant uploads the information sheet from a panel physician.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Only IRCC panel physician exams are accepted for immigration medical purposes."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about SDS document sequence?","options":["SDS files usually include upfront tuition payment, GIC, language results, and often upfront medical evidence where required.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"SDS depends on complete upfront evidence for streamlined processing."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about proof of tuition?","options":["Receipts or school account statements should clearly show amounts paid, program, and student identity.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Unclear payment proof can weaken the funds assessment."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about bank statements?","options":["Statements should be recent, traceable, and consistent with the applicant''s claimed source of funds.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Large unexplained deposits are often scrutinized for genuineness."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about sponsor documents?","options":["A sponsor package should connect the sponsor to the applicant and show income, assets, and willingness to pay.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Officers need both capacity and credible commitment from a financial sponsor."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about statement of purpose?","options":["A study plan should explain why the program, school, Canada, timing, and return plan make sense.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A strong SOP addresses the officer''s core concerns without contradicting the forms."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about education history?","options":["Transcripts, diplomas, and resumes should match the program level and career progression claimed.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Consistency between past studies and proposed studies supports genuineness."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about employment evidence?","options":["Employment letters, pay slips, or business records can explain career context and ties to the home country.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Work history can show why the Canadian program is a rational next step."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about travel history?","options":["Prior lawful travel can help but is not required; undisclosed refusals or overstays are serious problems.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Travel history is weighed with the full temporary resident assessment."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about police certificates?","options":["Police certificates are provided when requested by IRCC or the visa office checklist.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"They are part of admissibility screening, not a substitute for biometrics."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about translation requirements?","options":["Documents not in English or French generally need certified translations and copies of the original documents.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC must be able to verify and understand every submitted record."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about submission after refusal?","options":["A new application should address the refusal reasons with stronger evidence rather than simply resubmitting the same package.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Officers can see prior refusals and expect material improvements."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about processing times?","options":["Published processing times are estimates and do not guarantee a decision before the program start date.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should plan for delays and update IRCC if intake dates change."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about deferred admission?","options":["If the start date changes, the applicant should provide a deferral or updated LOA through the proper channel.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A stale LOA can raise concerns about whether the study plan remains valid."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about passport request?","options":["A passport request usually means IRCC needs the passport to place a visa counterfoil where one is required.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It is a late-stage step but applicants should still follow instructions carefully."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about approval package?","options":["The approval package may include a POE letter and, for visa-required nationals, a TRV counterfoil.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The actual study permit is issued at entry, so the approval documents must be carried."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about entering Canada?","options":["At the port of entry, the applicant should carry the POE letter, LOA, funds evidence, and updated school documents.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"CBSA may ask whether the applicant still meets the study permit conditions."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about changing DLIs?","options":["Post-secondary students must follow IRCC rules for changing schools and ensure the new school is a DLI.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"School changes can affect compliance reporting and future applications."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about dependant applications?","options":["Family member forms and evidence should be submitted consistently with the student''s plan and finances.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A family package is reviewed for each person''s purpose, funds, and admissibility."},{"level":2,"question":"For a study permit application made from outside Canada, what is the correct process point about client information uploads?","options":["Optional client information uploads should be organized, labelled, and used to clarify evidence that does not fit elsewhere.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A clear upload helps the officer review the file efficiently."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with a program that repeats prior education?","options":["The officer may doubt purpose if the applicant cannot explain why a similar or lower-level program is necessary now.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Study progression should be credible and tied to realistic goals."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with large unexplained deposits?","options":["The officer may treat sudden funds as borrowed or temporary unless the source is documented.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Funds must be available, traceable, and credible for the study period."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with weak home-country ties?","options":["The officer may refuse if employment, family, assets, or career prospects do not support departure after studies.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Temporary intent is assessed alongside the applicant''s personal circumstances."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with generic statement of purpose?","options":["A template SOP can undermine credibility because it fails to connect the program to the applicant''s real background.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers look for a coherent, individualized rationale."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with undisclosed visa refusals?","options":["Failure to disclose prior refusals can become misrepresentation even if the study plan is otherwise strong.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"IRCC asks about prior refusals and can compare records across countries."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with questionable DLI or program choice?","options":["A low-detail or inconsistent school choice can make the officer question whether the applicant is a genuine student.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The applicant should show why that DLI and program fit their goals."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with late application close to intake?","options":["A rushed application may be refused or become impractical if processing cannot finish before the start date.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Timing is not an eligibility rule by itself, but it affects credibility and logistics."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with family remaining in Canada after refusal?","options":["If accompanying family plans are unclear, the officer may worry the study plan is mainly a migration strategy.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Family circumstances must be explained consistently with temporary residence obligations."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with inconsistent employment dates?","options":["Conflicting resumes, forms, and letters can damage credibility and invite deeper verification.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Consistency across documents is essential in discretionary temporary resident decisions."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with unverified sponsor income?","options":["A sponsor with unclear income may not satisfy the officer that funds are truly available for tuition and living costs.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Sponsor evidence should show lawful source, liquidity, and relationship."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with course mismatch with career goals?","options":["The officer may ask why the applicant needs a Canadian credential if the program does not advance their stated career.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A persuasive file links studies to a plausible future benefit."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with poor academic performance?","options":["Weak grades are not an automatic refusal, but the applicant should show readiness for the proposed program.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Academic history can affect whether the study plan appears realistic."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with language weakness?","options":["If language evidence is weak for the program, the officer may doubt the applicant can complete studies successfully.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Language readiness supports both admission and genuine student assessment."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with using agents and false documents?","options":["Documents remain the applicant''s responsibility even if an agent prepared the file.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Misrepresentation findings can apply when the applicant signs or submits false information."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with expired passport before program end?","options":["The permit may be shortened, creating future extension risk and avoidable administrative problems.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Passport validity should align with the expected study period where possible."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with missing PAL or TAL?","options":["If no exemption applies, missing attestation can make the application incomplete or ineligible for processing.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Attestation requirements are a threshold issue for many post-secondary applicants."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with SDS evidence not meeting SDS rules?","options":["A file labelled SDS without required proof may be processed outside SDS or refused if core requirements are missing.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"SDS speed depends on strict upfront compliance."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with dual intent handled poorly?","options":["Saying the applicant will never leave Canada can undermine the temporary resident requirement.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Dual intent must still include a credible plan to comply if PR is not granted."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with prior overstay or non-compliance?","options":["Past breaches can weigh heavily against future compliance unless clearly explained and resolved.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers assess whether the applicant will obey Canadian immigration conditions."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with unrealistic living-cost budget?","options":["Funds that barely cover tuition and ignore rent, food, insurance, and travel may fail the sufficiency test.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"IRCC expects a realistic financial plan for the whole stay."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with medical inadmissibility concerns?","options":["Medical results can delay or affect approval if they raise public health or excessive demand issues.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Study permit decisions include admissibility, not only school acceptance."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with changed program after approval?","options":["A major change at entry can trigger questions about whether the approval basis still exists.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The applicant should carry updated documents and comply with school-change rules."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with work being the real purpose?","options":["If the file emphasizes wages over education, the officer may doubt the applicant is a bona fide student.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Study permits are for study first, with work only as a conditional benefit."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with documents that cannot be verified?","options":["Unverifiable employment, bank, or school records can lead to refusal or procedural fairness concerns.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Authenticity is a core officer concern in high-volume temporary resident processing."},{"level":3,"question":"Officer perspective in a study permit application made from outside Canada: what is the key issue with port of entry inconsistencies?","options":["A different story at the airport can cause CBSA to question admissibility or decline to issue the permit.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The approval letter does not remove the need to satisfy entry examination."}],"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Show clients which pages to scan — MRZ visible, no glare, full spread.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample LOA / DLI letter (mock)","description":"Designated Learning Institution acceptance — program and dates.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample GIC certificate (mock)","description":"SDS financial requirement — approved bank GIC.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample IELTS / PTE TRF (mock)","description":"Language scores for SDS / Non-SDS discussion.","mimeType":"image/jpeg","docKind":"language"},{"title":"Sample SOP specimen (mock)","description":"Structure for genuine student intent — course fit and career plan.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample academic transcripts (mock)","description":"Marksheets with backlogs explanation guidance.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample sponsor affidavit (mock)","description":"Parent sponsor ITR-linked financial undertaking.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample bank statement (mock)","description":"6-month statement with name, account number, and closing balance — explain seasoning.","mimeType":"application/pdf","docKind":"financial"}],"navBucket":"visa","donts":{"dos":["Confirm DLI and program details match LOA before submission","Use country-specific SDS checklist when eligible","Explain biometrics and medical steps with dates to client in writing","Keep seasoned funds evidence for Non-SDS cases","Attach logical SOP tied to career plan and home-country ties"],"donts":["Do not submit without signed client checklist and fee receipt where policy requires","Do not promise SDS timelines if client is Non-SDS","Do not use expired LOA or wrong tuition figures on forms","Do not hide previous refusals from other countries","Do not quote government fees without checking current IRCC fee page"],"mistakes":["Recent large deposits without source explanation","Copy-paste SOP not matching course or prior academics","Missing sponsor income proof or weak employment letters","Uploading blurry scans or inconsistent names across documents","Missing BIL deadline for biometrics"]}}'::jsonb, updated_at = now()
WHERE id = 'c35e6051-f40f-47bf-9cac-0a386c47a336';

UPDATE public.service_library
SET academy_metadata = '{"displayName":"Canada – Visitor Visa (TRV)","shortDescription":"IRCC temporary resident visa · Tourism, family, business · Biometrics may apply","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Beginner","learningMinutes":15,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current IRCC visitor visa fee (CAD $100) and biometrics fee on canada.ca before quoting clients."},"alert":{"title":"Purpose must match documents","body":"Tourism, family visit, and business visitor files need different evidence. Misaligned purpose is a common refusal reason—align invitation, itinerary, and cover letter."},"tags":[{"label":"Active service","variant":"success"},{"label":"Ties evidence critical","variant":"warning"},{"label":"2–8 weeks","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"2–8 weeks processing","variant":"neutral"},{"label":"CAD $100 + biometrics","variant":"neutral"},{"label":"Strong ties required","variant":"warning"},{"label":"Online application","variant":"success"}],"kpis":[{"label":"Processing time","value":"2–8w","sub":"Varies by country of residence","tone":"primary"},{"label":"Government fee","value":"CAD $100","sub":"+ biometrics CAD $85 if required","tone":"warning"},{"label":"Our approval rate","value":"78%","sub":"~65% industry benchmark","tone":"success"},{"label":"Required docs","value":"10","sub":"+ invitation if applicable","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & third-party","tone":"primary"}],"about":[{"label":"Description","value":"Temporary Resident Visa (TRV) allowing Indian nationals to visit Canada for tourism, family visits, or short business trips. Most applications are submitted online through the IRCC portal."},{"label":"Eligible applicants","value":"Valid passport · Genuine temporary purpose · Strong ties to India · Sufficient funds · Clean immigration history"},{"label":"Single vs multiple entry","value":"Officer decides entry type and validity at approval. Do not promise multiple-entry unless client profile supports it.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"TRV counterfoil in passport; client must respect stay duration and purpose. Overstay affects future Canada applications."}],"eligibility":[{"criterion":"Valid passport (6+ months validity recommended)","met":true,"note":"Check expiry before booking VAC appointment"},{"criterion":"Proof of purpose (tourism / family / business)","met":true,"note":"Itinerary, invitation letter, or business documents as applicable"},{"criterion":"Proof of funds for trip duration","met":true,"note":"Bank statements, ITR, sponsor letter if applicable"},{"criterion":"Strong ties to home country","met":true,"note":"Employment, property, family, business—document clearly"},{"criterion":"Biometrics completed","met":false,"note":"Book within 30 days of BIL if required"},{"criterion":"Medical exam (if required)","met":false,"note":"Based on residence history and stay plans"},{"criterion":"No prior misrepresentation or serious inadmissibility","met":true}],"redFlagsBanner":"If refused, do not reapply immediately with the same weak ties evidence. Address the specific refusal reason before a new submission.","redFlags":[{"title":"Weak home-country ties","description":"Unemployed applicant with no property, family, or business ties; vague return plan.","fix":"Document employment, business, property, family obligations; employer leave letter","severity":"Very common"},{"title":"Insufficient or unseasoned funds","description":"Large recent deposits, funds not matching income, or no sponsor proof.","fix":"4–6 month bank history; sponsor ITR + employment letter; explain large credits","severity":"Very common"},{"title":"Purpose mismatch","description":"Tourism file with business documents only, or family visit without host invitation.","fix":"Align purpose, cover letter, itinerary, and supporting documents","severity":"Common"},{"title":"Previous refusals not addressed","description":"Canada or other country refusals hidden or not explained in cover letter.","fix":"Full disclosure + changed circumstances + stronger evidence","severity":"High"},{"title":"Overstated stay or vague itinerary","description":"Long stay without credible reason or no hotel/flight bookings where appropriate.","fix":"Realistic itinerary; explain accommodation; show return ticket intent","severity":"Common"},{"title":"Biometrics deadline missed","description":"BIL expired before VAC appointment completed.","fix":"Book biometrics within days of BIL; track confirmation","severity":"Medium"}],"faqs":[{"q":"Can we guarantee approval for a strong profile?","a":"No. IRCC officers assess each case individually. We can improve file quality but never promise approval."},{"q":"How much funds should a tourist show?","a":"Enough to cover flights, accommodation, and daily expenses for the planned stay. Verify current IRCC guidance; typically CAD $2,000–5,000+ depending on duration and who pays."},{"q":"Is an invitation letter mandatory for family visits?","a":"Not always legally required, but strongly recommended when visiting relatives. Host should provide invitation, status proof, and address details."},{"q":"Can a refused applicant reapply?","a":"Yes, when circumstances or evidence materially improve. Reapply without addressing refusal reasons usually fails again."},{"q":"Does TRV allow work in Canada?","a":"No. TRV is for temporary visit only. Work requires a work permit unless exempt."},{"q":"How long can a visitor stay?","a":"Officer sets duration at port of entry—often up to 6 months per entry. Client must not overstay."},{"q":"When should biometrics be done?","a":"As soon as possible after Biometric Instruction Letter, typically within 30 days."},{"q":"Can TRV be used to join a spouse studying in Canada?","a":"Sometimes, but assess whether visitor visa or dependant permit is more appropriate. Separate pathways may apply."}],"compliance":["Paid representation in Canada may require RCIC or lawyer—confirm who signs client agreement","Client service agreement and consent must be on file before submission","Never guarantee visa approval; use approved-language only in marketing","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Build ties evidence first—employment letter, property papers, family documents","Match cover letter tone to purpose; avoid generic templates","Book biometrics within days of BIL to avoid preventable delays","For family visits, verify host''s status in Canada before submission","Save final PDF package in client binder for audit"],"postApproval":["Send TRV details and entry conditions to client in writing","Remind client of permitted stay duration and no-work rule","Advise on travel insurance and port-of-entry documents to carry","Register for pre-departure briefing if offered"],"performance":{"ourRate":78,"industryRate":65,"stats":[{"label":"Files this year","value":"96"},{"label":"Approved","value":"75"},{"label":"Refused","value":"15"},{"label":"Withdrawn","value":"6"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":78,"benchmark":65},{"label":"Ties documentation","ours":74,"benchmark":58},{"label":"Financial credibility","ours":76,"benchmark":62},{"label":"Complete checklist first submit","ours":88,"benchmark":68}],"timeline":[{"weeks":"1","title":"Counseling, purpose assessment, fee agreement"},{"weeks":"1–2","title":"Document collection, cover letter, financials"},{"weeks":"2–3","title":"Quality review & IRCC submission"},{"weeks":"3–4","title":"Biometrics (if applicable)"},{"weeks":"2–8","title":"IRCC processing"}],"relatedServices":[{"label":"Canada – Student Visa (Study Permit)","libraryId":""},{"label":"Canada – Super Visa","libraryId":""},{"label":"Canada – Spouse Visa","libraryId":""}],"changelog":[{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial counselor content for Canada TRV with 2026 fee and processing notes."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Indian TRV refusals often cite ties—always collect employer leave letter and property/family evidence even for tourism."},{"author":"Quality","date":"6 Jun 2026","text":"Second review required for all files with prior Canada refusal."}],"resources":[{"title":"IRCC — Visit Canada as a tourist","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada.html","description":"Official visitor visa requirements and how to apply"},{"title":"IRCC — Temporary resident visa","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada/apply-visitor-visa.html","description":"Application steps and document checklist"},{"title":"IRCC — Biometrics","url":"https://www.canada.ca/en/immigration-refugees-citizenship/campaigns/biometrics/facts.html","description":"When biometrics are required and how to book"},{"title":"IRCC processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current estimates by country and application type"},{"title":"IRCC — Fee list","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigration-citizenship-application-fees.html","description":"Current government fees for visitor visa and biometrics"}],"quiz":[{"level":1,"question":"In a temporary resident visa visitor application, which statement about the meaning of a TRV is correct?","options":["A TRV is a visa counterfoil that lets a visa-required foreign national travel to a Canadian port of entry.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"It supports travel to Canada but does not itself guarantee admission."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about the visitor visa fee is correct?","options":["The standard temporary resident visa application fee is CAD $100 per person, plus biometrics if required.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The CAD $100 fee is separate from biometrics and other service charges."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about visitor status is correct?","options":["Visitor status allows a temporary stay for tourism, family visits, or other permitted non-work purposes.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A visitor must respect the authorized period and conditions of stay."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about ties to home country is correct?","options":["Employment, family, property, studies, and financial obligations can help show the applicant will leave Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"TRV decisions focus heavily on whether the visit is temporary."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about purpose of visit is correct?","options":["The purpose should be clear, credible, and supported by itinerary, invitation, or event evidence where relevant.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A vague purpose makes it harder for an officer to assess temporary intent."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about financial support is correct?","options":["The applicant must show enough money for travel, living costs, and return transportation.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Funds can come from the applicant or a credible host, but evidence must be clear."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about entry versus visa validity is correct?","options":["A valid TRV permits travel to seek entry; the border officer decides admission and length of stay.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Visa validity is not the same as guaranteed status inside Canada."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about biometrics is correct?","options":["Most TRV applicants aged 14 to 79 must give biometrics unless exempt or still valid from a prior application.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Biometrics support identity and security screening."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about medical exam is correct?","options":["A medical exam may be required for longer stays, certain countries, or planned work in sensitive settings.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Medical requirements depend on risk factors and IRCC instructions."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about invitation letters is correct?","options":["An invitation letter can support the purpose of visit but does not guarantee approval.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The visitor still must prove their own eligibility and temporary intent."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about host documents is correct?","options":["Host status, address, relationship, and financial documents may help explain the visit and support arrangements.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Host evidence is useful when the host is paying or providing accommodation."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about family visits is correct?","options":["Visiting family is a valid purpose if the timeline, relationship, and return plan are credible.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Family in Canada can support a visit but may also increase overstay concerns if not explained."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about tourism is correct?","options":["Tourism can be a valid purpose when the itinerary, funds, and travel history fit the applicant''s circumstances.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Officers assess whether the trip is realistic and temporary."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about business visitors is correct?","options":["Business visitors may attend meetings or conferences but cannot enter the Canadian labour market without authorization.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Permitted business activities are narrower than working in Canada."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about super visa distinction is correct?","options":["A super visa is different from a regular TRV and is designed for parents and grandparents of citizens or permanent residents.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Super visa eligibility and insurance requirements are distinct from ordinary visitor visas."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about multiple-entry visas is correct?","options":["IRCC often issues multiple-entry TRVs, but each entry is still examined by CBSA.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Multiple-entry validity does not remove the need to comply with visitor conditions."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about passport validity is correct?","options":["The visa cannot normally be valid beyond the passport expiry date.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Passport expiry can limit the visa even when the applicant otherwise qualifies."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about previous refusals is correct?","options":["Prior refusals must be disclosed truthfully in the application.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Non-disclosure can create a misrepresentation problem worse than the refusal itself."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about criminality is correct?","options":["Criminal convictions or charges can make a visitor inadmissible.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"TRV applicants are screened for admissibility as well as purpose and funds."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about work prohibition is correct?","options":["A visitor cannot work in Canada unless specifically authorized under immigration rules.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Visitor status is not a substitute for a work permit."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about study limits is correct?","options":["Visitors can generally study only in short courses of six months or less unless exempt or authorized.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Longer programs usually require a study permit."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about dependants is correct?","options":["Each accompanying family member needs their own application and must satisfy the officer.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Approval of one visitor does not automatically approve every family member."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about travel history is correct?","options":["Lawful travel history can support credibility, but lack of travel history is not an automatic refusal.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Travel history is one factor among funds, ties, and purpose."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about authorized stay is correct?","options":["If no specific date is stamped or documented, many visitors are authorized for up to six months from entry.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"CBSA can impose a shorter or different period at examination."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about leaving Canada is correct?","options":["The applicant must convince the officer they will leave Canada at the end of the authorized visit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"This is the core temporary resident requirement for visitor visas."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about IMM 5257?","options":["IMM 5257 is the main application form for a temporary resident visa made outside Canada.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It records identity, travel purpose, background, and admissibility information."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about family information?","options":["IMM 5707 or IMM 5645 may be required depending on the applicant''s country and checklist.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Family information helps IRCC verify identity and relationships."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about document checklist?","options":["The applicant should follow both the IRCC portal checklist and any country-specific instructions.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Local visa office requirements can add important documents."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about fee payment?","options":["The applicant pays the CAD $100 TRV fee online, and biometrics fees if required.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Payment is part of completing submission and triggering processing steps."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about biometrics instruction letter?","options":["After submission and biometrics fee payment, IRCC issues a letter used to book biometrics at a VAC or ASC.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should not assume biometrics are complete until enrolled and reflected in the account."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about purpose evidence?","options":["Travel itinerary, invitation letters, event registrations, or hotel bookings should match the stated purpose.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Documents should tell the same story as the application forms."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about employment letters?","options":["A strong employment letter confirms role, salary, approved leave, and expected return date.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Employment evidence supports both funds and home-country ties."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about business ownership proof?","options":["Business registration, tax records, invoices, and bank statements can support self-employment ties.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Self-employed applicants need documents that explain ongoing obligations at home."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about bank documents?","options":["Recent statements should show stable balances, income deposits, and enough funds for the trip.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Officers often scrutinize sudden unexplained deposits."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about host support?","options":["If the host pays expenses, the file should include the host''s invitation, status, income, and accommodation evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Host support does not eliminate the need for the applicant''s own credible plan."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about travel itinerary?","options":["An itinerary should be realistic for the length of stay and the applicant''s budget.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Overly long or expensive plans can raise concerns if funds are limited."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about passport submission?","options":["A passport request is used to place the visa counterfoil for visa-required applicants.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The passport must usually be valid and have space for the counterfoil."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about processing times?","options":["Published TRV times are estimates and vary by country, volume, biometrics, and background checks.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should not book non-refundable travel assuming a specific decision date."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about medical instructions?","options":["If IRCC requests a medical exam, the applicant must use a panel physician and follow the deadline.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Medical compliance is part of admissibility processing."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about police or court records?","options":["Police certificates or court records may be needed when criminal history is disclosed or requested.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Incomplete criminality evidence can delay or derail a TRV."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about translation?","options":["Non-English or non-French documents generally need certified translations with the original document.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Officers need readable and reliable evidence."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about proof of relationship?","options":["Birth certificates, marriage certificates, photos, and communication records can prove the host relationship.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Relationship evidence helps explain why the visit is happening."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about minor applicants?","options":["Minors may need consent letters, custody documents, and travel authorization from non-accompanying parents.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC and border officers assess child travel safety and consent."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about reapplying after refusal?","options":["A reapplication should respond directly to refusal reasons with better evidence or changed circumstances.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Repeating the same file usually produces the same concerns."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about address history?","options":["Address and travel histories should be complete and consistent with passports and employment records.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Inconsistencies can create credibility issues."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about biometrics validity?","options":["Visitor biometrics are often valid for 10 years and may be reused if still valid.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should check validity before paying or attending again."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about IRCC webform?","options":["A webform can update material changes, but it should not be used as a substitute for a complete initial package.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Important documents belong in the application whenever possible."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about group applications?","options":["Family members can be submitted together, but each person''s forms, fees, and evidence must be complete.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"TRV eligibility is assessed individually."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about decision documents?","options":["Approval leads to passport submission or visa issuance, while refusal letters identify the main concerns.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should read the decision carefully before taking next steps."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about arrival examination?","options":["At arrival, the visitor should be ready to explain purpose, funds, host, and return plans consistently.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"CBSA can ask questions even after a TRV is issued."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with an overlong visit request?","options":["A visit that is unusually long for the stated purpose may make the officer doubt the applicant''s real intent.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Trip length should match employment leave, funds, and reason for travel."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with weak employment evidence?","options":["Generic or unverifiable employment letters may fail to prove a strong reason to return home.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers rely on credible, verifiable ties."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with family all travelling together?","options":["If the whole household travels with few remaining ties, the officer may see higher overstay risk.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Applicants should explain remaining obligations and return plans."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with a host paying everything?","options":["Full host sponsorship can help costs but may not overcome weak personal funds 