SET academy_metadata = '{"displayName":"Canada – Work Permit (LMIA & LMIA-Exempt)","shortDescription":"IRCC work permit · Employer-sponsored · LMIA or exempt category","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":25,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current work permit fees on canada.ca. LMIA processing via ESDC adds significant time and employer cost."},"alert":{"title":"LMIA vs LMIA-exempt","body":"Most employer-specific permits require LMIA from ESDC unless exempt (ICT, CUSMA, PGWP, etc.). Verify category before quoting timeline."},"tags":[{"label":"Active service","variant":"success"},{"label":"Employer sponsorship","variant":"warning"},{"label":"3–9 months","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"LMIA may required","variant":"warning"},{"label":"CAD $155 worker fee","variant":"neutral"},{"label":"Job offer needed","variant":"success"},{"label":"Biometrics","variant":"neutral"}],"kpis":[{"label":"Processing time","value":"3–9m","sub":"LMIA + IRCC combined","tone":"primary"},{"label":"Government fee","value":"CAD $155","sub":"Worker fee + biometrics","tone":"warning"},{"label":"Our approval rate","value":"86%","sub":"~78% benchmark","tone":"success"},{"label":"Required docs","value":"15","sub":"+ LMIA if applicable","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & LMIA","tone":"primary"}],"about":[{"label":"Description","value":"Employer-specific or open work permit allowing foreign nationals to work in Canada. LMIA-required streams need positive LMIA from Employment and Social Development Canada (ESDC)."},{"label":"Eligible applicants","value":"Valid job offer from Canadian employer · LMIA or exempt category · Qualifying skills/experience · Medical/biometrics as required"},{"label":"LMIA process","value":"Employer must advertise, recruit, and demonstrate no Canadians available. ESDC LMIA adds weeks to months before IRCC application.","warning":true},{"label":"Key authority","value":"ESDC (LMIA) · IRCC (work permit)"},{"label":"After approval","value":"Work for specified employer (closed permit) or open category. Maintain status; employer compliance with LMIA conditions."}],"eligibility":[{"criterion":"Valid job offer / contract","met":true},{"criterion":"LMIA positive or exempt category confirmed","met":false,"note":"Employer responsibility for LMIA"},{"criterion":"Qualifying work experience/education","met":true},{"criterion":"Medical exam (if required)","met":false},{"criterion":"Biometrics completed","met":false},{"criterion":"No criminal inadmissibility","met":true},{"criterion":"Employer compliance history","met":true,"note":"Verify employer legitimacy"}],"redFlagsBanner":"If LMIA refused, address ESDC reasons before reapplication—do not submit IRCC work permit without positive LMIA when required.","redFlags":[{"title":"LMIA advertising deficiencies","description":"Employer did not meet recruitment advertising requirements.","fix":"Ensure ESDC advertising compliance before LMIA submit","severity":"Very common"},{"title":"Wrong NOC/ wage offer","description":"Job classification or wage below median for region.","fix":"Verify TEER and prevailing wage on Job Bank","severity":"Common"},{"title":"Fake job offer","description":"Employer not genuine or employee-payback schemes.","fix":"Verify employer legitimacy; avoid fraudulent job offers","severity":"High"},{"title":"Medical/biometrics overdue","description":"Not completed within IRCC deadlines.","fix":"Book immediately after instructions","severity":"Common"},{"title":"Prior status violations","description":"Overstay or unauthorized work history.","fix":"Address inadmissibility; legal counsel if needed","severity":"High"},{"title":"Closed permit employer change","description":"Worker switching employers without new permit.","fix":"New LMIA and work permit for e