nformally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Evidence can turn a red flag into an understandable circumstance."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with officer weighing discretion?","options":["The officer looks for lawful status, genuine continued study, sufficient funds, and compliance with past conditions.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A strong extension file answers all four themes clearly."}],"donts":{"dos":["File before the current permit expires whenever possible","Collect current enrolment proof and transcript","Show credible funds for tuition and living costs","Explain program changes and study gaps","Calendar the new expiry date after approval"],"donts":["Do not advise work if status is uncertain","Do not file with expired enrolment evidence","Do not ignore restoration if permit expired","Do not promise approval or exact processing time","Do not overlook passport expiry"],"mistakes":["Applying after expiry without restoration forms","Missing DLI enrolment letter","Unexplained failed terms or withdrawals","Weak bank history with recent deposits","Requesting extension beyond passport validity"]},"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Identity page with passport validity visible.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample current study permit (mock)","description":"Shows permit conditions and expiry date.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample enrolment letter (mock)","description":"DLI confirmation of active enrolment and expected completion.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample transcript (mock)","description":"Academic progress evidence for extension review.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample tuition receipt (mock)","description":"Paid tuition or outstanding fee statement.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample bank statement (mock)","description":"Recent bank history with balance and account holder name.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample sponsor affidavit (mock)","description":"Sponsor commitment with source of income support.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample explanation letter (mock)","description":"Explains delayed completion, program change, or study gap.","mimeType":"application/pdf","docKind":"academic"}],"navBucket":"visa"}'::jsonb, updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000018';

UPDATE public.service_library
SET academy_metadata = '{"displayName":"Canada – Visitor Record (In-Canada Extension)","shortDescription":"IRCC visitor record · Extend stay in Canada · Temporary resident status","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Beginner","learningMinutes":14,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current visitor record fee, processing time, and maintained status guidance on canada.ca before counseling."},"alert":{"title":"Visitor record is not a visa","body":"A visitor record extends or changes status inside Canada. It does not replace a TRV or eTA for re-entry."},"tags":[{"label":"Active service","variant":"success"},{"label":"In-Canada extension","variant":"warning"},{"label":"2–4 months","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"2–4 months processing","variant":"neutral"},{"label":"CAD $100 approx","variant":"neutral"},{"label":"Extend visitor status","variant":"success"},{"label":"No work or study","variant":"warning"}],"kpis":[{"label":"Processing time","value":"2–4m","sub":"Check IRCC","tone":"primary"},{"label":"Government fee","value":"CAD $100","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our approval rate","value":"89%","sub":"~80% benchmark","tone":"success"},{"label":"Required docs","value":"9","sub":"+ reason for stay","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Visitor record application for temporary residents already in Canada who need to extend their stay as visitors or change conditions from another temporary status."},{"label":"Eligible applicants","value":"In Canada · Valid temporary resident status or restoration eligibility · Genuine temporary purpose · Funds for stay · Clear departure or next-status plan"},{"label":"Important limitation","value":"Visitor record does not authorize work or long-term study and does not guarantee re-entry after travel outside Canada.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Client receives a document with a new status expiry date. Review conditions and calendar the next exit or extension deadline."}],"eligibility":[{"criterion":"Client is physically in Canada","met":true},{"criterion":"Current visitor, student, or worker status is valid or restorable","met":true,"note":"Check original entry date and permit expiry"},{"criterion":"Clear temporary reason for extended stay","met":true},{"criterion":"Proof of funds for extended visit","met":true},{"criterion":"Accommodation or host support evidence","met":true},{"criterion":"No unauthorized work or study planned","met":true},{"criterion":"Ties outside Canada or credible departure plan","met":true},{"criterion":"Passport valid for requested stay period","met":true},{"criterion":"Prior status history and refusals disclosed","met":true}],"redFlagsBanner":"Visitor record files are refused when the reason for staying longer is vague, funds are weak, or the client appears to be living in Canada without a temporary plan.","redFlags":[{"title":"Vague extension reason","description":"Client says only they want to stay longer without dates, purpose, or supporting evidence.","fix":"Document visit purpose, timeline, funds, and departure or next-status plan","severity":"Very common"},{"title":"Status already expired","description":"Client missed the allowed stay or permit expiry date.","fix":"Assess restoration eligibility and stop unauthorized activities","severity":"High"},{"title":"Working as visitor","description":"Evidence suggests unauthorized employment or remote work issue.","fix":"Escalate before filing and prepare honest disclosure strategy","severity":"High"},{"title":"Weak funds","description":"Insufficient money for accommodation, food, insurance, and return travel.","fix":"Add bank history, sponsor letter, host proof, and budget explanation","severity":"Common"},{"title":"Long serial extensions","description":"Multiple back-to-back visitor records with no clear temporary end point.","fix":"Explain exceptional need or assess a more suitable immigration pathway","severity":"Common"},{"title":"TRV confusion","description":"Client believes visitor record allows re-entry after travel.","fix":"Explain visitor record vs TRV/eTA in writing before submission","severity":"Medium"},{"title":"Passport expiring","description":"Requested stay goes beyond passport validity.","fix":"Renew passport first where timeline allows","severity":"Medium"}],"faqs":[{"q":"Is a visitor record the same as a visitor visa?","a":"No. A visitor record extends status inside Canada. A TRV or eTA is used for travel to Canada."},{"q":"When should a visitor record be filed?","a":"File before the authorized stay expires. For entry without a stamp, calculate the default stay carefully unless another date was given."},{"q":"Can the client work on a visitor record?","a":"No. A visitor record does not authorize work unless a separate policy or permit applies."},{"q":"Can the client study on a visitor record?","a":"Only limited short-term study may be allowed in specific cases. Do not advise long-term study without a study permit."},{"q":"Can the client leave Canada while it is processing?","a":"Travel can abandon the practical purpose of the application and re-entry requires a valid TRV/eTA if applicable. Review before travel."},{"q":"How long should we request?","a":"Request a reasonable period supported by purpose, funds, insurance, and passport validity. Avoid arbitrary long requests."},{"q":"What if the client is waiting for another application?","a":"Explain the pending application and include proof, but still show temporary intent and funds."},{"q":"Can parents of students extend as visitors?","a":"Yes, if they show a genuine temporary purpose, funds, accommodation, and intention to leave or maintain legal status."},{"q":"What if the client has a prior refusal?","a":"Disclose it and address the refusal reason. Do not refile with the same weak explanation."},{"q":"Does approval guarantee future entry to Canada?","a":"No. Border entry is assessed separately, and a visitor record does not replace travel authorization."}],"compliance":["Client service agreement and consent must be on file before submission","Never imply visitor record authorizes work or long-term study","Never guarantee approval or future re-entry","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Calculate visitor expiry from stamp, visitor record, or six-month default carefully","Prepare a one-page stay plan with purpose, dates, funds, and exit plan","Use host documents only when they genuinely support accommodation and expenses","Warn clients in writing that visitor record is not a travel visa","Escalate serial extensions before filing another weak visitor request","Include travel insurance when medical or elderly visitor risk is relevant"],"postApproval":["Send visitor record expiry date and conditions to client","Explain no work or unauthorized study in writing","Calendar next departure or extension deadline","Confirm TRV/eTA needs before any travel outside Canada","Review next-status plan if client is waiting for family, study, or work application"],"performance":{"ourRate":89,"industryRate":80,"stats":[{"label":"Files this year","value":"112"},{"label":"Approved","value":"100"},{"label":"Refused","value":"9"},{"label":"Withdrawn","value":"3"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":89,"benchmark":80},{"label":"Temporary purpose clarity","ours":88,"benchmark":72},{"label":"Funds and accommodation","ours":87,"benchmark":75},{"label":"Status deadline control","ours":93,"benchmark":79}],"timeline":[{"weeks":"1","title":"Status expiry and purpose screening"},{"weeks":"1–2","title":"Funds, host, travel, and explanation documents"},{"weeks":"2","title":"IRCC online submission"},{"weeks":"2–4m","title":"IRCC processing and status monitoring"}],"relatedServices":[{"label":"Canada – Visitor Visa","libraryId":""},{"label":"Canada – Study Permit Extension","libraryId":""},{"label":"Canada – Spouse / Dependent Open Work Permit","libraryId":""}],"changelog":[{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial visitor record counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Always explain that visitor record extends in-Canada status only. Re-entry requires separate travel authorization."}],"resources":[{"title":"IRCC — Extend your stay as a visitor","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada/extend-stay.html","description":"Official visitor record application instructions"},{"title":"IRCC — After you apply to extend your stay","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada/extend-stay/after-apply.html","description":"Maintained status and after-apply guidance"},{"title":"IRCC — Restore your status as a visitor","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada/extend-stay/restore-status.html","description":"Restoration instructions for expired status"},{"title":"IRCC — Visit Canada","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada.html","description":"Visitor visa and entry overview"},{"title":"IRCC — Processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current visitor record processing estimates"},{"title":"IRCC — Pay your fees","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/pay-fees.html","description":"Current visitor extension fee page"}],"quiz":[{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about what a visitor record is is correct?","options":["A visitor record is an inside-Canada status document that authorizes a visitor to remain longer.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"It is proof of visitor status in Canada, not a travel visa."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about visitor record versus TRV is correct?","options":["A visitor record extends stay in Canada, while a TRV allows a visa-required person to travel to Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Confusing status and entry documents is a common error."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about who applies is correct?","options":["A person in Canada as a visitor applies when they want to remain beyond their authorized stay.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The application is made before current visitor status expires whenever possible."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about application fee is correct?","options":["The standard fee to extend stay as a visitor is CAD $100.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The visitor record fee is distinct from biometrics or restoration fees."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about maintained status is correct?","options":["A timely visitor record application can allow the person to remain in Canada under the same conditions while waiting.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Maintained status applies when a complete extension is filed before expiry."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about work prohibition is correct?","options":["A visitor record does not authorize work in Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Visitors must obtain work authorization unless an exemption applies."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about study limits is correct?","options":["A visitor record generally does not authorize long-term study beyond visitor study exemptions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Most programs over six months require a study permit."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about authorized stay after entry is correct?","options":["Many visitors receive up to six months unless CBSA stamps a different date or issues a record.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The person''s actual deadline depends on entry documents and officer decisions."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about proof of funds is correct?","options":["The applicant must show enough money to support the extended stay and leave Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Visitor extensions still require financial sufficiency."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about reason for extension is correct?","options":["A clear temporary reason, such as more tourism, family support, or changed travel plans, should be documented.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC assesses why more time is needed."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about passport validity is correct?","options":["A visitor record cannot normally be issued beyond the passport expiry date.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Passport validity can limit the requested extension."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about medical insurance is correct?","options":["Insurance is not always mandatory for ordinary visitor records but can support longer stays and medical-risk concerns.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Health coverage helps show the person can manage costs while visiting."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about family in Canada is correct?","options":["Family support can explain the visit but does not remove the need for temporary intent.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC still asks whether the visitor will leave when required."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about restoration is correct?","options":["If visitor status expired, restoration may be needed instead of a simple extension.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Restoration carries different requirements and fees."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about 90-day restoration window is correct?","options":["Restoration is generally available only within 90 days after status is lost.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Missing this window can require leaving Canada."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about entry visa after visitor record is correct?","options":["A visitor record does not help a visa-required person re-enter Canada after travel abroad.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A valid TRV is still needed for travel to Canada."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about conditions is correct?","options":["A visitor record may list conditions such as no work, no study, and a must-leave-by date.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The holder must follow all conditions."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about online submission is correct?","options":["Visitor record applications are commonly submitted online through IRCC.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Online filing provides proof of submission and account messages."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about biometrics is correct?","options":["Biometrics may be required if the applicant has not already provided valid biometrics and is not exempt.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC will issue instructions if biometrics are needed."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about medical exam is correct?","options":["IRCC may request a medical exam for longer stays or specific risk factors.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Medical admissibility can affect visitor extensions."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about departure plan is correct?","options":["The applicant should show a realistic plan to leave Canada at the end of the extended stay.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Temporary intent remains central."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about host support is correct?","options":["A Canadian host can provide accommodation or financial support evidence.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Host support should be documented and credible."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about multiple extensions is correct?","options":["Multiple visitor record approvals are possible but each new request must be justified.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Repeated extensions can raise concerns about living in Canada as a visitor."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about application outcome is correct?","options":["Approval results in a visitor record with a new expiry date; refusal ends any maintained status.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The applicant must act quickly after a refusal."},{"level":1,"question":"In a visitor record application to extend stay in Canada, which statement about status document delivery is correct?","options":["The visitor record is usually mailed or otherwise issued as a status document after approval.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The document should be checked for dates and conditions."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about IMM 5708?","options":["IMM 5708 is the main form to change conditions, extend stay, or remain in Canada as a visitor.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It is the standard inside-Canada visitor record form."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about filing before expiry?","options":["Submitting before the authorized stay ends is the safest way to preserve maintained status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Late filing changes the case into a restoration problem."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about calculating expiry?","options":["The expiry may be the date on a stamp, visitor record, or six months from entry if no date was imposed.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants must know their actual status deadline."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about passport pages?","options":["The application commonly includes passport identity pages and entry stamps or travel history evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC uses these documents to confirm identity and current status."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about financial documents?","options":["Bank statements, pay records from abroad, host support, or savings evidence should cover the requested extension.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The money must be credible and available."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about host invitation?","options":["A host letter should explain relationship, address, support offered, and why the extension is temporary.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A detailed host letter helps connect the facts."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about purpose explanation?","options":["A cover letter should explain why the applicant needs more time and when they will leave.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Clear facts are more useful than a generic request."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about return travel proof?","options":["A return ticket or planned itinerary can support departure intent, though it is not the only proof.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The officer wants a realistic end point for the stay."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about medical insurance upload?","options":["Insurance evidence can support a longer stay, especially for older visitors or medical-risk concerns.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It helps address potential cost concerns."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about family documents?","options":["Marriage, birth, or relationship proof should be included when the extension is based on family visits.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Relationship evidence supports the stated purpose."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about biometrics instruction?","options":["If biometrics are needed, IRCC sends a biometrics instruction letter after submission.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The applicant must complete biometrics by the deadline."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about medical request deadline?","options":["A medical request must be completed through a panel physician by the deadline.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Ignoring a request can lead to refusal."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about restoration fee?","options":["A restoration case must include the restoration fee in addition to the visitor extension fee.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The fee structure signals that the applicant is asking to regain status."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about no work evidence?","options":["The applicant should avoid submitting facts that imply unauthorized employment during the visit.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Unauthorized work can damage the extension request."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about study plans?","options":["If the person plans long-term study, they should consider a study permit rather than a visitor record.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Visitor records are not a workaround for study permit requirements."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about spouse or child applicants?","options":["Each family member needs their own visitor record request if each needs extended status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Status is individual even when applications are connected."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about proof of current status?","options":["The current entry stamp, prior visitor record, or other status document should be included.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC needs evidence the person is eligible to extend from inside Canada."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about processing time?","options":["Processing times are estimates, and maintained status may continue while a timely application is pending.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The applicant should keep proof of submission."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about leaving while pending?","options":["Leaving Canada can make the visitor record request less useful because it is for status inside Canada.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A visitor record is not a re-entry document."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about approval review?","options":["After approval, the applicant should check the expiry date and conditions on the visitor record.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Any error should be addressed promptly."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about refusal response?","options":["If refused, the applicant should assess restoration, departure, or other status options immediately.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Maintained status ends when the refusal is made."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about address updates?","options":["The applicant should keep their Canadian mailing address current with IRCC.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Visitor records and requests may depend on correct contact details."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about support from abroad?","options":["If foreign income supports the stay, documents should show continued employment, leave, or remote funds source.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Foreign ties can support both funds and departure intent."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about document translations?","options":["Non-English or non-French evidence should include certified translations.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Untranslated documents may be unusable to the officer."},{"level":2,"question":"For a visitor record application to extend stay in Canada, what is the correct process point about webform updates?","options":["Material changes such as a new passport or changed departure date should be updated through proper IRCC channels.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The officer should decide on current and accurate facts."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with using visitor status to live in Canada?","options":["Repeated long extensions can make the officer conclude the person is residing in Canada rather than visiting.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Visitor status is temporary and limited in purpose."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with applying after expiry?","options":["A late application cannot create maintained status and may require restoration.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The status timeline is often the first issue the officer checks."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with unauthorized work indicators?","options":["References to Canadian clients, wages, or job duties can trigger refusal and compliance concerns.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Visitor records do not authorize work."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with caregiving without authorization?","options":["Helping family is allowed in ordinary family ways, but providing regular unpaid or paid caregiving can look like work.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The facts determine whether the activity enters the labour market."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with no departure plan?","options":["A request with no clear end date or reason to leave may fail the temporary resident test.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Extensions should still have a credible finish point."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with weak funds after long stay?","options":["Dwindling funds can lead the officer to question how the visitor will support themselves and leave.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Financial sufficiency is reassessed for the extended period."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with host with limited income?","options":["If the host cannot realistically support the visitor, host sponsorship may carry little weight.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Support promises need evidence of capacity."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with passport expiring soon?","options":["A short passport may limit approval or make the requested period impossible.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The document cannot normally outlast passport validity."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with medical treatment purpose?","options":["Medical treatment visits need strong evidence of treatment plan, payment ability, and temporary intent.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Medical purpose cases raise cost, duration, and admissibility questions."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with pregnancy and birth tourism concerns?","options":["A visitor seeking to remain for childbirth should disclose facts honestly and prove funds and temporary intent.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Non-disclosure or inability to pay medical costs can be serious."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with criminal charge in Canada?","options":["New criminality can affect admissibility and status extension.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Inside-Canada visitor applications still involve admissibility review."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with conflicting entry history?","options":["Inconsistent dates about entry, exits, and status expiry can undermine credibility.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The officer needs a reliable status chronology."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with restoration after working?","options":["Restoration may be refused if the applicant violated conditions such as unauthorized work.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Restoration is discretionary and compliance matters."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with travel during pending extension?","options":["Departing Canada can interrupt the practical benefit of a pending visitor record and may require a TRV to return.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The record is an inside-Canada status document."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with TRV mistaken for extension?","options":["A valid TRV in the passport does not extend visitor status inside Canada.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"This misunderstanding often leads to accidental overstays."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with family sponsorship pending?","options":["A pending sponsorship does not automatically give visitor status.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The applicant must still maintain or restore temporary status."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with dual intent?","options":["Wanting PR can coexist with a visitor extension only if the person will leave if required.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Dual intent must be explained carefully."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with documents showing permanent move?","options":["Shipping household goods, ending foreign employment, or enrolling children long-term can suggest non-temporary intent.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers compare conduct with the claimed visitor purpose."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with multiple family members extending?","options":["When an entire family extends repeatedly, the officer may ask what ties remain outside Canada.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The larger pattern affects temporary intent."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with failure to answer document request?","options":["Ignoring IRCC requests can cause refusal even if the original reason for extension was valid.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Procedural compliance is part of a successful file."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with false host letter?","options":["A false invitation or support letter can lead to misrepresentation findings.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Authenticity is central to discretionary visitor decisions."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with unexplained emergency extension?","options":["Emergency reasons should be supported by evidence such as medical, airline, or family documents.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Unsupported emergencies may look like excuses to remain."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with remote work for foreign employer?","options":["Remote work while visiting can be fact-specific and should not involve entering the Canadian labour market.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers may scrutinize whether the visitor is effectively working from Canada."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with school-aged children?","options":["Children studying in Canada may need proper authorization depending on the situation.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A visitor record for the parent does not automatically solve the child''s study status."},{"level":3,"question":"Officer perspective in a visitor record application to extend stay in Canada: what is the key issue with officer balancing factors?","options":["The officer weighs current status, purpose, funds, compliance history, and likelihood of departure.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A strong visitor record file answers each of those concerns directly."}],"donts":{"dos":["Calculate status expiry before filing","Document a clear temporary stay reason","Show funds and accommodation support","Explain visitor record vs TRV/eTA","Calendar next expiry after approval"],"donts":["Do not say visitor record allows work","Do not treat visitor record as a re-entry visa","Do not file serial extensions without strategy","Do not hide prior refusals or overstays","Do not request unsupported long stays"],"mistakes":["Calculating six-month stay incorrectly","Using vague reason for extension","Missing host support documents","Ignoring expired status restoration","Client travels without valid TRV/eTA"]},"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Passport identity page and Canadian entry stamps if relevant.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample entry stamp / prior permit (mock)","description":"Evidence used to calculate authorized stay.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample stay plan letter (mock)","description":"Purpose, requested dates, funds, host details, and exit plan.","mimeType":"application/pdf","docKind":"travel"},{"title":"Sample bank statement (mock)","description":"Funds available for extended visit.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample host invitation letter (mock)","description":"Host accommodation and support details.","mimeType":"application/pdf","docKind":"travel"},{"title":"Sample host proof of status (mock)","description":"Host PR card, citizenship proof, or valid permit as applicable.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample travel insurance (mock)","description":"Insurance proof for extended stay risk management.","mimeType":"application/pdf","docKind":"travel"},{"title":"Sample return plan evidence (mock)","description":"Return ticket, employment leave, family ties, or next-status explanation.","mimeType":"application/pdf","docKind":"travel"}],"navBucket":"visa"}'::jsonb, updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000019';

UPDATE public.service_library
SET academy_metadata = '{"displayName":"Canada – CAIPS / GCMS Notes Request","shortDescription":"IRCC ATIP · GCMS notes · Refusal analysis · Case history","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Beginner","learningMinutes":12,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current ATIP eligibility, consent requirements, and processing timelines on canada.ca before ordering notes."},"alert":{"title":"Consent and requester eligibility required","body":"GCMS notes usually require an eligible requester in Canada or proper consent from the applicant. Do not request without signed authorization."},"tags":[{"label":"Active service","variant":"success"},{"label":"Consent required","variant":"warning"},{"label":"30+ days","variant":"neutral"},{"label":"Online – ATIP","variant":"neutral"}],"chips":[{"label":"30+ days processing","variant":"neutral"},{"label":"CAD $5 approx","variant":"neutral"},{"label":"Refusal insight","variant":"success"},{"label":"Not an appeal","variant":"warning"}],"kpis":[{"label":"Processing time","value":"30d+","sub":"ATIP timelines vary","tone":"primary"},{"label":"Government fee","value":"CAD $5","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our completion rate","value":"98%","sub":"Consent-driven service","tone":"success"},{"label":"Required docs","value":"8","sub":"+ consent form","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Access to Information and Privacy request for CAIPS/GCMS notes, used to review officer notes, refusal rationale, application status, and case history for Canadian immigration files."},{"label":"Eligible applicants","value":"Applicant with signed consent · Eligible requester in Canada where required · Correct IRCC application identifiers · Identity proof"},{"label":"Service scope","value":"GCMS notes provide records and officer comments but do not overturn a refusal or speed up processing.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC) and Government of Canada ATIP Online Request Service"},{"label":"After release","value":"Counselor reviews notes for refusal reasons, missing evidence, credibility concerns, and next application strategy."}],"eligibility":[{"criterion":"Signed consent from applicant or authorized person","met":true,"note":"Use current consent form"},{"criterion":"Requester eligibility confirmed for ATIP submission","met":true},{"criterion":"Applicant identity details match IRCC records","met":true},{"criterion":"Application number, UCI, or file details available","met":true},{"criterion":"Refusal letter or application history collected where relevant","met":true},{"criterion":"Applicant understands notes are not an appeal","met":true},{"criterion":"Privacy authorization and service agreement on file","met":true},{"criterion":"Correct department and record type selected in ATIP portal","met":true},{"criterion":"Delivery email and client contact details verified","met":true}],"redFlagsBanner":"Do not order GCMS notes without consent, correct identifiers, and clear expectations about what notes can and cannot do.","redFlags":[{"title":"No signed consent","description":"Applicant has not authorized the requester to access personal immigration records.","fix":"Collect current signed consent and identity proof before submitting","severity":"High"},{"title":"Requester not eligible","description":"ATIP requester may not meet Canada presence or status requirements for access request.","fix":"Use eligible requester or correct Privacy Act route as applicable","severity":"High"},{"title":"Wrong application identifiers","description":"UCI, application number, name spelling, or date of birth does not match IRCC record.","fix":"Cross-check refusal letter, portal screenshots, and passport before filing","severity":"Common"},{"title":"Client expects reversal","description":"Client believes ordering notes will reopen or approve the case.","fix":"Explain notes are informational and plan separate reconsideration or reapplication if needed","severity":"Very common"},{"title":"Urgent deadline missed","description":"Appeal, judicial review, or school deferral deadline may arrive before notes.","fix":"Escalate immediately; do not wait for notes if legal deadline is near","severity":"High"},{"title":"Wrong department selected","description":"Request submitted to the wrong institution or for wrong record type.","fix":"Select IRCC and specify immigration application records","severity":"Medium"},{"title":"Outdated consent form","description":"Consent form is missing signature, date, representative details, or applicant data.","fix":"Reissue consent form and verify every required field","severity":"Common"}],"faqs":[{"q":"What are GCMS notes?","a":"They are internal immigration records and officer notes from IRCC systems, often used to understand refusals or case status."},{"q":"Are CAIPS and GCMS the same?","a":"Clients often use the terms together. GCMS is the modern system most IRCC notes come from; CAIPS is an older term still used colloquially."},{"q":"How long do notes take?","a":"ATIP requests are commonly targeted around 30 days, but extensions and delays happen. Check the official ATIP process."},{"q":"Can GCMS notes overturn a refusal?","a":"No. Notes help diagnose reasons. Any reconsideration, appeal, judicial review, or reapplication is separate."},{"q":"Who can request notes?","a":"Eligibility depends on access to information and privacy rules. Often an eligible requester in Canada submits with applicant consent."},{"q":"What documents are needed?","a":"Signed consent, applicant identity details, passport, refusal letter or application details, UCI, application number, and requester information."},{"q":"Can we order notes for an application still in process?","a":"Yes, but notes may be limited or outdated by the time received. Manage expectations."},{"q":"Will notes show the exact reason for refusal?","a":"Often they provide more detail than the refusal letter, but some information may be redacted or procedural."},{"q":"Should we wait for notes before reapplying?","a":"For refusals, notes are helpful. But if intake, visa, or legal deadlines are urgent, escalate and decide strategically."},{"q":"Can family members sign for the applicant?","a":"Only if legally authorized. Otherwise each adult applicant generally signs their own consent."}],"compliance":["Signed consent and privacy authorization must be on file before ATIP request","Never promise that notes will reverse a decision or guarantee future approval","Protect GCMS notes as sensitive personal information","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Collect refusal letter and portal screenshots before drafting ATIP request","Use exact passport name, date of birth, UCI, and application number","Warn clients that notes may be delayed or partially redacted","Review notes against the original application package, not in isolation","Flag judicial review or appeal deadlines before waiting for notes","Store released notes securely with restricted access"],"postApproval":["Download and save GCMS notes securely in the client binder","Summarize officer concerns in plain language for the client","Map each refusal concern to evidence needed for next filing","Schedule strategy call for reapplication, reconsideration, or legal referral","Delete or restrict duplicate copies according to privacy policy"],"performance":{"ourRate":98,"industryRate":92,"stats":[{"label":"Files this year","value":"154"},{"label":"Released","value":"151"},{"label":"Returned","value":"2"},{"label":"Withdrawn","value":"1"}]},"approvalFactors":[{"label":"Completion vs benchmark","ours":98,"benchmark":92},{"label":"Consent accuracy","ours":97,"benchmark":88},{"label":"Identifier matching","ours":96,"benchmark":85},{"label":"Actionable review notes","ours":90,"benchmark":75}],"timeline":[{"weeks":"1","title":"Consent, identity, and file details collection"},{"weeks":"1","title":"ATIP portal submission"},{"weeks":"4–8","title":"Government processing and possible extension"},{"weeks":"5–9","title":"Notes review and strategy summary"}],"relatedServices":[{"label":"Canada – Student Visa","libraryId":""},{"label":"Canada – Visitor Visa","libraryId":""},{"label":"Canada – Express Entry PR","libraryId":""}],"changelog":[{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial CAIPS / GCMS notes counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"GCMS service is privacy-sensitive. No consent, no request. Notes support strategy but are not a remedy by themselves."}],"resources":[{"title":"Government of Canada — ATIP Online Request","url":"https://atip-aiprp.apps.gc.ca/atip/welcome.do","description":"Official online access to information request portal"},{"title":"IRCC — Access to information and privacy","url":"https://www.canada.ca/en/immigration-refugees-citizenship/corporate/transparency/access-information-privacy.html","description":"IRCC ATIP overview"},{"title":"Government of Canada — Make an access to information request","url":"https://www.canada.ca/en/treasury-board-secretariat/services/access-information-privacy/access-information/request-information.html","description":"Who can request and how the process works"},{"title":"Government of Canada — Privacy Act requests","url":"https://www.canada.ca/en/treasury-board-secretariat/services/access-information-privacy/privacy/request-personal-information.html","description":"Requesting personal information under privacy rules"},{"title":"IRCC — Use of a representative","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigration-citizenship-representative/use-representative.html","description":"Representative and authorization guidance"},{"title":"Government of Canada — Access to Information Act","url":"https://laws-lois.justice.gc.ca/eng/acts/A-1/","description":"Legal framework for access requests"}],"quiz":[{"level":1,"question":"What are CAIPS or GCMS notes?","options":["Internal immigration file notes released through an access request","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"CAIPS is older terminology; GCMS notes help explain IRCC file history."},{"level":1,"question":"What does GCMS stand for?","options":["Global Case Management System","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS is IRCC''s case management system."},{"level":1,"question":"Why request GCMS notes after refusal?","options":["To understand officer concerns and refusal reasoning","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes can reveal details beyond a standard refusal letter."},{"level":1,"question":"What does ATIP stand for?","options":["Access to Information and Privacy","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"ATIP is the process for requesting government records."},{"level":1,"question":"Who can usually make an ATIP request directly?","options":["A Canadian citizen, permanent resident, or person/entity in Canada","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access requests usually require a qualified requester."},{"level":1,"question":"What is a consent form used for?","options":["Authorizing release of the applicant''s information to the requester","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Consent is needed when someone requests another person''s personal records."},{"level":1,"question":"What is the common ATIP response target?","options":["About 30 days, subject to extensions","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"ATIP is associated with a 30-day target, but extensions and delays occur."},{"level":1,"question":"Do GCMS notes overturn a refusal by themselves?","options":["No, they provide information only","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes are diagnostic and do not reopen or approve a file automatically."},{"level":1,"question":"Which file types can notes help analyze?","options":["Visitor, study, work, PR, sponsorship, and citizenship-related files","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS notes can be useful across many immigration file types."},{"level":1,"question":"What information helps locate a file?","options":["UCI, application number, name, and date of birth","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Accurate identifiers help locate the correct record."},{"level":1,"question":"What is a UCI?","options":["Unique Client Identifier","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"A UCI is an IRCC client number."},{"level":1,"question":"What can officer notes contain?","options":["Assessment comments, concerns, eligibility review, and processing history","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes may show how documents and eligibility were assessed."},{"level":1,"question":"Why might information be redacted?","options":["Law permits withholding sensitive or third-party information","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access laws allow exemptions for security, privacy, and other protected information."},{"level":1,"question":"What is CAIPS older terminology linked to?","options":["Legacy immigration computer notes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"People still say CAIPS, but many modern records are GCMS."},{"level":1,"question":"When are GCMS notes especially helpful?","options":["After a refusal or long delay where reasons are unclear","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes can identify real issues in refusals or delays."},{"level":1,"question":"What fee is commonly associated with access requests?","options":["A small government fee","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access to Information requests usually involve a modest fee."},{"level":1,"question":"Which document proves consent for a representative request?","options":["Signed consent from the applicant","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Signed consent authorizes disclosure to the requester."},{"level":1,"question":"What is refusal analysis?","options":["Reviewing the decision record to identify weaknesses and next steps","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Analysis compares reasons, documents, and notes."},{"level":1,"question":"Can notes show eligibility status?","options":["They may show assessments such as eligibility, criminality, or security","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Internal statuses often appear, though some fields may be redacted."},{"level":1,"question":"Why must request details be accurate?","options":["Wrong details can delay or misdirect the request","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Accurate identifiers prevent incomplete results."},{"level":1,"question":"How does a refusal letter compare with GCMS notes?","options":["It usually gives a shorter summary","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS notes can provide more internal detail."},{"level":1,"question":"Which agency commonly holds IRCC application notes?","options":["Immigration, Refugees and Citizenship Canada","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"IRCC holds many immigration application records."},{"level":1,"question":"What can a representative do with notes?","options":["Advise on reapplication, reconsideration, or litigation strategy","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes support strategy but do not decide the case."},{"level":1,"question":"Why is the application number useful?","options":["It identifies the specific application","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Application numbers help target the exact file."},{"level":1,"question":"Which statement about notes is correct?","options":["They are useful but may be redacted, delayed, or limited","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes provide transparency but not every desired detail."},{"level":2,"question":"What is first before requesting notes for someone else?","options":["Obtain signed consent from the applicant","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Privacy rules require authorization for third-party release."},{"level":2,"question":"Which details should be collected for ATIP?","options":["Full name, date of birth, UCI, application number, and file type","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Complete identifiers help find the correct records."},{"level":2,"question":"Why choose the correct institution?","options":["The request must go to the department holding the records","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"IRCC notes should generally be requested from IRCC."},{"level":2,"question":"What should be reviewed with GCMS notes?","options":["The refusal letter and full submitted application package","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Comparing all records gives a better diagnosis."},{"level":2,"question":"Why can recent notes be incomplete?","options":["System updates may not capture every detail immediately","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Timing affects what appears in released notes."},{"level":2,"question":"How can notes help before reapplying?","options":["They target new evidence to actual officer concerns","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"A reapplication can be more focused and responsive."},{"level":2,"question":"What does a consent form commonly include?","options":["Applicant identity, requester details, signature, and scope","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Consent should clearly authorize release."},{"level":2,"question":"Why might ATIP extend beyond 30 days?","options":["Large volume, consultations, or allowed operational reasons","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access laws permit extensions in certain cases."},{"level":2,"question":"Which field may reveal the deciding concern?","options":["Eligibility or final assessment comments","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Assessment comments often explain why the officer was not satisfied."},{"level":2,"question":"How are notes different from reconsideration?","options":["Notes disclose records; reconsideration asks IRCC to revisit a decision","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"They are separate processes."},{"level":2,"question":"When might CBSA notes be useful?","options":["When border, enforcement, or security records may be relevant","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Some records are held by CBSA rather than IRCC."},{"level":2,"question":"How should redactions be treated?","options":["Recognize legal limits and infer cautiously","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Redactions limit certainty."},{"level":2,"question":"Why is the original package important?","options":["It shows what evidence the officer had","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Analysis must consider the record before the decision-maker."},{"level":2,"question":"What can a criminality or medical status field indicate?","options":["A processing stage or assessment result","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS statuses can show progress or concerns in context."},{"level":2,"question":"How should weak-ties notes be used?","options":["Add specific home-country evidence and explain temporary purpose","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"New evidence should address the identified concern."},{"level":2,"question":"What does insufficient-funds language suggest?","options":["The officer was not satisfied finances supported the application","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Financial concerns need clearer credible evidence."},{"level":2,"question":"Why do timelines matter in refusal analysis?","options":["They separate facts before the decision from later changes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Old and new evidence support different strategies."},{"level":2,"question":"What if the wrong file is returned?","options":["Submit a corrected request with accurate identifiers","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Correct details help obtain the intended record."},{"level":2,"question":"Which next step may be time-sensitive?","options":["Judicial review deadline","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Court deadlines can be short and are not paused by ATIP."},{"level":2,"question":"Why not wait for notes if a legal deadline is near?","options":["Missing the deadline may eliminate that remedy","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"ATIP requests do not necessarily extend court deadlines."},{"level":2,"question":"What is a focused ATIP request?","options":["A request specifying the file, period, and records needed","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Focused requests reduce confusion."},{"level":2,"question":"What can an in-Canada requester do?","options":["Submit an access request with the applicant''s consent","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"A qualified requester can request records but cannot decide the case."},{"level":2,"question":"Which document anchors refusal analysis?","options":["The refusal letter with date and application number","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"The refusal letter identifies the specific decision."},{"level":2,"question":"Why might multiple ATIP requests be needed?","options":["Different applications or agencies may have separate records","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Complex histories can require targeted requests."},{"level":2,"question":"What should a refusal analysis conclude?","options":["Specific weaknesses, evidence gaps, and viable next options","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Useful analysis turns notes into practical strategy."},{"level":3,"question":"Why can notes be insufficient for judicial review alone?","options":["Court review has its own record and legal reasonableness test","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS notes help strategy but do not replace litigation rules."},{"level":3,"question":"What is risky about assuming redacted security content is harmless?","options":["Missing content may affect admissibility analysis","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Redactions limit visibility into sensitive assessments."},{"level":3,"question":"How can notes reveal document credibility issues?","options":["They may mention verification concerns or inconsistencies","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Officer comments can point to authenticity concerns."},{"level":3,"question":"Why should reapplications not merely argue the officer was wrong?","options":["They should provide stronger evidence addressing concerns","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Fixing evidence gaps is usually more useful than disagreement alone."},{"level":3,"question":"What is a limitation for very recent applications?","options":["Notes may show little activity if no substantive review occurred","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes only reflect records created by extraction."},{"level":3,"question":"What can study permit notes expose?","options":["Doubts about study plan, finances, ties, or progression","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes clarify temporary resident concerns."},{"level":3,"question":"What can sponsorship notes expose?","options":["Relationship genuineness, document gaps, or interview concerns","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Family-class notes may show relationship and admissibility analysis."},{"level":3,"question":"What is the danger of using notes to craft false evidence?","options":["Misrepresentation and long-term inadmissibility","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes should guide truthful clarification only."},{"level":3,"question":"Why read notes with program law in mind?","options":["Officer concerns must be mapped to the legal test","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Good analysis connects facts, law, and reasoning."},{"level":3,"question":"What suggests reconsideration may be difficult?","options":["The refusal was based on missing evidence not submitted before decision","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Reconsideration is harder when the original record was incomplete."},{"level":3,"question":"When may reconsideration be more plausible?","options":["When evidence was overlooked or a clear error occurred","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Reconsideration is strongest on existing-record errors."},{"level":3,"question":"Why are extraction dates important?","options":["They show when the notes snapshot was generated","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"The generation date affects interpretation."},{"level":3,"question":"What is a common interpretation issue?","options":["Distinguishing boilerplate from officer-specific reasoning","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Not every GCMS line is a substantive finding."},{"level":3,"question":"Why can boilerplate refusal reasons mislead?","options":["They may not identify precise concerns without internal notes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Generic reasons often require deeper analysis."},{"level":3,"question":"What if notes contradict the refusal letter?","options":["Analyze both and consider legal advice on reasonableness or fairness","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Contradictions can matter in context."},{"level":3,"question":"Why do ATIP extensions matter strategically?","options":["They may delay notes beyond reapplication or court planning deadlines","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Timing affects how notes can be used."},{"level":3,"question":"Which notes are most useful for diagnosis?","options":["Latest eligibility and final decision comments","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Final comments usually contain the clearest reasoning."},{"level":3,"question":"What can a bring-forward date indicate?","options":["An internal file review or action date","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Internal dates are not guaranteed decision dates."},{"level":3,"question":"Why separate old evidence from new evidence?","options":["It matters whether the officer had the evidence when deciding","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Legal options differ based on the decision record."},{"level":3,"question":"What is a risk of filing repeated ATIP requests too broadly?","options":["Delays and unfocused records that are hard to analyze","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Targeted requests are usually more useful."},{"level":3,"question":"How can notes help identify unreasonable reasoning?","options":["They may show conclusions unsupported by the submitted record","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Legal review focuses on whether reasons and outcome are justified."},{"level":3,"question":"Why should applicants preserve submitted packages?","options":["They are needed to compare with officer notes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Without the package, refusal analysis is incomplete."},{"level":3,"question":"What if notes show an officer misunderstood a document?","options":["A targeted reconsideration or reapplication explanation may address it","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"The response depends on timing and available remedies."},{"level":3,"question":"Why should analysis avoid overpromising based on notes?","options":["Notes can be partial, redacted, or ambiguous","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Responsible advice recognizes uncertainty."},{"level":3,"question":"What is the best advanced use of CAIPS/GCMS notes?","options":["Build an evidence-based strategy for reapplication, reconsideration, or review","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes are most useful when translated into a concrete next step."}],"donts":{"dos":["Collect signed consent before request","Verify UCI, application number, and name spelling","Explain notes are informational","Review notes against original submission","Protect records as sensitive personal data"],"donts":["Do not request without consent","Do not promise refusal reversal","Do not ignore appeal or judicial review deadlines","Do not submit with mismatched identifiers","Do not share notes with unauthorized parties"],"mistakes":["Missing applicant signature on consent","Wrong IRCC application number","Selecting wrong government institution","Waiting for notes despite urgent school deadline","Treating notes as a substitute for legal advice"]},"sampleDocs":[{"title":"Sample consent form (mock)","description":"Authorization for release of personal immigration information.","mimeType":"application/pdf","docKind":"compliance"},{"title":"Sample passport bio page (mock)","description":"Identity confirmation for applicant details.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample refusal letter (mock)","description":"Used to match application number and refusal date.","mimeType":"application/pdf","docKind":"immigration"},{"title":"Sample IRCC portal screenshot (mock)","description":"Shows application number, UCI, and submission status.","mimeType":"image/jpeg","docKind":"immigration"},{"title":"Sample requester proof of status (mock)","description":"Evidence for eligible requester where required.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample ATIP payment receipt (mock)","description":"Proof of government fee payment.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample GCMS notes release (mock)","description":"Redacted example of released officer notes.","mimeType":"application/pdf","docKind":"immigration"},{"title":"Sample refusal analysis memo (mock)","description":"Counselor summary mapping officer concerns to next steps.","mimeType":"application/pdf","docKind":"compliance"}],"navBucket":"visa"}'::jsonb, updated_at = now()
