SET academy_metadata = '{"displayName":"Canada – Spouse / Dependent Open Work Permit","shortDescription":"IRCC family work permit · Spouse or dependant · Open work authorization","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Intermediate","learningMinutes":18,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Spouse/dependent OWP rules change frequently. Verify principal applicant category, occupation/program eligibility, and dependant criteria on canada.ca before quoting."},"alert":{"title":"Principal applicant eligibility drives the file","body":"Do not assess spouse/dependent OWP in isolation. The principal worker, student, or PR applicant''s status and category determine eligibility."},"tags":[{"label":"Active service","variant":"success"},{"label":"Family eligibility","variant":"warning"},{"label":"3–5 months","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"3–5 months processing","variant":"neutral"},{"label":"CAD $255 approx","variant":"neutral"},{"label":"Open work permit","variant":"success"},{"label":"Principal status required","variant":"warning"}],"kpis":[{"label":"Processing time","value":"3–5m","sub":"Varies by applicant location","tone":"primary"},{"label":"Government fee","value":"CAD $255","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our approval rate","value":"88%","sub":"~76% benchmark","tone":"success"},{"label":"Required docs","value":"13","sub":"+ relationship proof","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Open work permit pathway for eligible spouses, common-law partners, or qualifying dependants linked to a principal applicant''s Canadian work, study, or immigration status."},{"label":"Eligible applicants","value":"Genuine spouse/common-law partner or eligible dependant · Principal applicant has qualifying status · Relationship documents · Funds and admissibility evidence"},{"label":"Rule sensitivity","value":"Eligibility for spouses of students and workers depends on current IRCC categories, program level, occupation, and principal status. Always verify current rules.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Applicant may work for most employers in Canada subject to printed conditions. Review expiry alignment with principal applicant status."}],"eligibility":[{"criterion":"Principal applicant has valid qualifying status in Canada or approved pathway","met":true},{"criterion":"Applicant is spouse, common-law partner, or qualifying dependant under IRCC rules","met":true},{"criterion":"Relationship is genuine and well documented","met":true,"note":"Marriage certificate alone may not be enough"},{"criterion":"Principal worker occupation, employer, or permit category qualifies where required","met":true},{"criterion":"Principal student program and institution qualify where required","met":true},{"criterion":"Applicant passport valid for requested permit period","met":true},{"criterion":"Applicant has no inadmissibility, misrepresentation, or undisclosed refusal issue","met":true},{"criterion":"Funds or family support evidence available for settlement and stay","met":true},{"criterion":"Medical exam or biometrics completed if required","met":false}],"redFlagsBanner":"Most weak spouse/dependent OWP files fail because the principal applicant does not qualify, the relationship proof is thin, or prior refusals are not addressed.","redFlags":[{"title":"Principal applicant not eligible","description":"Principal worker, student, or PR applicant category does not support dependant OWP.","fix":"Verify current IRCC category before taking full file; assess visitor or other status options","severity":"High"},{"title":"Weak relationship proof","description":"Marriage certificate only, limited photos, no communication, or no shared life evidence.","fix":"Add relationship timeline, photos, chats, travel, financial, and family evidence","severity":"Very common"},{"title":"Recent marriage before filing","description":"Marriage occurred shortly before application with limited relationship history.","fix":"Prepare detailed relationship narrative and third-party corroboration","severity":"Common"},{"title":"Prior refusals not disclosed","description":"Applicant or principal has previous Canada or other country refusals omitted from forms.","fix":"Disclose all refusals and address changed circumstances","severity":"High"},{"title":"Principal status expiring soon","description":"Principal permit expires shortly, limiting dependant permit duration or eligibility.","fix":"Coordinate principal extension or wait for renewed status where strategic","severity":"Common"},{"title":"Insufficient funds","description":"Family cannot show credible support for living costs in Canada.","fix":"Add bank history, employment income, pay stubs, and sponsor explanation","severity":"Medium"},{"title":"Inconsistent forms","description":"Dates, addresses, marital status, or family details conflict across forms.","fix":"Run consistency review against passport, marriage, and prior applications","severity":"Common"}],"faqs":[{"q":"Can every spouse of a student get an open work permit?","a":"No. Eligibility depends on current IRCC rules, the student''s program and institution, and other conditions."},{"q":"Can every spouse of a worker get an open work permit?","a":"No. The principal worker''s occupation, permit type, and status must qualify under current policy."},{"q":"Is a marriage certificate enough?","a":"Usually not by itself. Provide relationship history, photos, communication, travel, financial ties, and family evidence where available."},{"q":"Can common-law partners apply?","a":"Yes, if they meet IRCC''s common-law definition and can prove cohabitation and genuine relationship."},{"q":"Can dependent children get open work permits?","a":"Only in limited circumstances. Many children need visitor or study status instead. Screen age and dependency rules carefully."},{"q":"Should the application be filed together with the principal applicant?","a":"Sometimes. It depends on timing, principal eligibility, documents, and risk. Joint filing can help context but is not always best."},{"q":"How long will the OWP be valid?","a":"Often tied to the principal applicant''s status and passport validity. IRCC decides the final duration."},{"q":"Can the applicant work while waiting?","a":"Only if they already have authorization and meet maintained status rules. Outside-Canada applicants cannot work until approved and admitted with proper status."},{"q":"What if there was a previous spouse OWP refusal?","a":"Order notes if useful, address refusal reasons directly, and strengthen principal eligibility and relationship evidence."},{"q":"Does approval lead to PR?","a":"No. OWP is temporary status. It may support Canadian work experience, but PR requires a separate pathway."}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee open work permit approval or work rights before authorization","Confirm paid representation authority for Canadian immigration filings","Fee quotes must separate consultancy, government, biometrics, medical, and third-party costs"],"proTips":["Screen the principal applicant first before building the dependant file","Create a relationship timeline with dates matching forms and documents","Use current IRCC rules for spouses of students and workers before quoting eligibility","Coordinate expiry dates between principal and dependant passports","Address prior refusals in the cover letter instead of hoping they are ignored","Run a final consistency check across all family forms"],"postApproval":["Send approval and permit condition summary to applicant","Explain work restrictions printed on the permit, if any","Coordinate travel, TRV/eTA, and port of entry steps where applicable","Review SIN application or update process after arrival/approval","Calendar expiry alongside principal applicant status"],"performance":{"ourRate":88,"industryRate":76,"stats":[{"label":"Files this year","value":"86"},{"label":"Approved","value":"76"},{"label":"Refused","value":"8"},{"label":"Withdrawn","value":"2"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":88,"benchmark":76},{"label":"Principal eligibility","ours":90,"benchmark":72},{"label":"Relationship evidence","ours":86,"benchmark":70},{"label":"Form consistency","ours":92,"benchmark":78}],"timeline":[{"weeks":"1","title":"Principal eligibility and relationship screening"},{"weeks":"1–3","title":"Relationship, status, funds, and form preparation"},{"weeks":"3","title":"Quality review and IRCC submission"},{"weeks":"3–5m","title":"IRCC processing, biometrics, and decision"}],"relatedServices":[{"label":"Canada – Student Visa","libraryId":""},{"label":"Canada – BOWP","libraryId":""},{"label":"Canada – Visitor Record","libraryId":""}],"changelog":[{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial spouse / dependent OWP counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Do not quote spouse OWP eligibility until the principal applicant category is verified under current IRCC instructions."}],"resources":[{"title":"IRCC — Work permits for family members","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/permit/temporary/family-members.html","description":"Official family member work permit eligibility"},{"title":"IRCC — Open work permits","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/permit/temporary/open-work-permit.html","description":"Open work permit overview and restrictions"},{"title":"IRCC — Work permit from inside Canada","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/permit/temporary/apply.html","description":"Work permit application instructions"},{"title":"IRCC — Biometrics","url":"https://www.canada.ca/en/immigration-refugees-citizenship/campaigns/biometrics/facts.html","description":"Biometrics requirement and validity"},{"title":"IRCC — Processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current work permit processing estimates"},{"title":"IRCC — Pay your fees","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/pay-fees.html","description":"Current work permit and open work permit holder fees"}],"quiz":[{"level":1,"question":"What is a spouse or dependent open work permit?","options":["An open work permit for an eligible spouse or partner of a qualifying worker or student","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"The permit can allow the spouse or partner to work for most employers."},{"level":1,"question":"What is the key advantage of an open work permit?","options":["It is not tied to one named employer","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Open permits provide labour-market flexibility subject to conditions."},{"level":1,"question":"Which relationship is commonly relevant?","options":["Spouse or common-law partner","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Eligibility usually depends on a genuine qualifying relationship."},{"level":1,"question":"Can dependent children always get open work permits through this category?","options":["No, children''s options depend on age, status, and program rules","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Dependent children may need visitor, study, or other authorization depending on facts."},{"level":1,"question":"What does C41 commonly relate to?","options":["Spouses of certain skilled workers","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"C41 has been used for spouse open work permit eligibility connected to skilled workers."},{"level":1,"question":"What does C42 commonly relate to?","options":["Spouses of certain international students","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"C42 has been used for spouse open work permits connected to qualifying students."},{"level":1,"question":"Does an open work permit guarantee entry to Canada?","options":["No, entry is still assessed separately","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"A permit approval does not remove admissibility or border assessment."},{"level":1,"question":"Who issues spouse open work permits?","options":["Immigration, Refugees and Citizenship Canada","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"IRCC assesses and issues work permits."},{"level":1,"question":"What must the principal worker or student usually have?","options":["Valid status and qualifying work or study circumstances","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"The spouse''s eligibility depends on the principal applicant''s qualifying situation."},{"level":1,"question":"Which document proves marriage?","options":["Marriage certificate","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Civil status documents help prove the spousal relationship."},{"level":1,"question":"How is common-law partnership usually shown?","options":["Cohabitation and shared-life evidence for the required period","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Common-law cases need evidence beyond a simple statement."},{"level":1,"question":"What type of work permit is the spouse permit normally?","options":["Open work permit","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"It usually allows work for most employers."},{"level":1,"question":"Does a spouse OWP require an LMIA?","options":["No, it is generally LMIA-exempt when eligibility is met","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"The category relies on an exemption rather than a labour market test."},{"level":1,"question":"Can a spouse OWP holder work for any employer without limits?","options":["Most employers, subject to printed conditions and restricted sectors","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Open permits still include conditions such as medical restrictions."},{"level":1,"question":"What is a dependent child in immigration terms?","options":["A child meeting IRCC age and dependency rules","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Dependent-child status is defined by regulation and policy."},{"level":1,"question":"Why is the principal applicant''s status important?","options":["It is the basis for the spouse''s eligibility","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"If the principal does not qualify, the spouse application may fail."},{"level":1,"question":"What does OWP stand for?","options":["Open Work Permit","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"OWP is the abbreviation for open work permit."},{"level":1,"question":"Is a job offer usually required for a spouse OWP?","options":["No, not usually","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"The permit is open and normally not based on a specific employer."},{"level":1,"question":"What should a spouse OWP applicant prove about the relationship?","options":["That it is genuine and legally recognized or common-law","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Relationship credibility is central to the application."},{"level":1,"question":"Can spouses apply from outside Canada?","options":["Yes, if they meet the rules for their situation","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Location can affect forms and travel documents but does not by itself prove eligibility."},{"level":1,"question":"What is a principal applicant in this context?","options":["The worker or student whose status supports the spouse''s application","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"The spouse''s application is derivative of the principal''s qualifying status."},{"level":1,"question":"What happens when the principal permit expires soon?","options":["The spouse permit may be limited or refused if eligibility is not durable","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Validity often follows the principal applicant''s authorization."},{"level":1,"question":"What does a spouse OWP not grant by itself?","options":["Permanent residence","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"It is temporary worker status, not PR."},{"level":1,"question":"Why check current IRCC rules before applying?","options":["Spouse OWP eligibility categories change over time","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Policy changes can affect workers, students, and family members."},{"level":1,"question":"Which proof is useful for a spouse of a worker?","options":["Principal worker''s permit, job details, and proof of employment","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"The application must show the principal worker qualifies."},{"level":2,"question":"What should be included for a spouse of a skilled worker?","options":["Principal work permit, employment letter, pay stubs, and relationship proof","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Evidence should show both qualifying employment and a genuine relationship."},{"level":2,"question":"What should be included for a spouse of a student?","options":["Study permit, enrollment proof, program details, and relationship proof","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"The student spouse''s eligibility depends on qualifying study circumstances."},{"level":2,"question":"Why are pay stubs useful?","options":["They show the principal worker is actively employed","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Active employment evidence can support worker-based eligibility."},{"level":2,"question":"Why is an enrollment letter useful?","options":["It confirms the principal student is actively studying in a qualifying program","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Student-based spouse OWPs require evidence of qualifying study."},{"level":2,"question":"How should a common-law couple document cohabitation?","options":["Lease, bills, IDs, bank records, and affidavits where appropriate","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Multiple records can prove shared residence and partnership."},{"level":2,"question":"What if the marriage is recent?","options":["Provide stronger evidence of relationship history and genuineness","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Recent marriages may need more context and supporting documents."},{"level":2,"question":"Which forms should be consistent?","options":["Names, dates, addresses, family information, and status details","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"Consistency reduces credibility concerns."},{"level":2,"question":"Why is passport validity important?","options":["The work permit cannot be issued beyond passport validity","A closed LMIA work permit only","A visitor visa with no work rights","A permanent resident card"],"correctIndex":0,"explanation":"A short passport can shorten the spouse permit."},{"level":2,"question":"What is maintained status for a spouse OWP extension?","options":["Status that may continue after a timely extension 